"/** Accretion disk: radial gradient on a ring (for RingGeometry UV) */
function createDiskTexture(colorA: string, colorB: string): THREE.CanvasTexture {
  const S = 512;
  const canvas = document.createElement('canvas');
  canvas.width = S; canvas.height = S;
  const ctx = canvas.getContext('2d')!;
  ctx.clearRect(0, 0, S, S);
  const c = S / 2;
  // Annular glow
  const g = ctx.createRadialGradient(c, c, c * 0.28, c, c, c * 0.95);
  g.addColorStop(0.0,  colorA.replace('rgb(', 'rgba(').replace(')', ', 0.0)'));
  g.addColorStop(0.15, colorA.replace('rgb(', 'rgba(').replace(')', ', 0.85)'));
  g.addColorStop(0.45, colorB.replace('rgb(', 'rgba(').replace(')', ', 0.55)'));
  g.addColorStop(0.75, colorB.replace('rgb(', 'rgba(').replace(')', ', 0.15)'));
  g.addColorStop(1.0,  'rgba(0,0,0,0)');
  ctx.fillStyle = g;
  ctx.fillRect(0, 0, S, S);
  return new THREE.CanvasTexture(canvas);
}
